// API 사용량 종합 분석
const aligoRaw = $('알리고 SMS 잔여량').first().json || {};
const oracleRaw = $('Oracle 디스크 + MinIO').first().json?.stdout || $('Oracle 디스크 + MinIO').first().json?.result || '';
const minipcRaw = $('미니PC 디스크').first().json?.stdout || $('미니PC 디스크').first().json?.result || '';
const execData = $('n8n 실행 로그').first().json?.data || [];

const now = new Date();
const weekStart = new Date(now); weekStart.setDate(now.getDate() - 7);
const alerts = [];

// 알리고 SMS 잔여량
const smsRemain = aligoRaw.SMS_CNT || aligoRaw.remain || aligoRaw.smsCnt || '?';
const lmsRemain = aligoRaw.LMS_CNT || aligoRaw.lmsCnt || '?';
const mmsRemain = aligoRaw.MMS_CNT || aligoRaw.mmsCnt || '?';
const smsNum = parseInt(smsRemain) || 0;
if (smsNum > 0 && smsNum < 100) alerts.push(`SMS 잔여 ${smsNum}건 부족`);

// Oracle 디스크
let oracleDiskPct = '?';
try {
  const diskLine = oracleRaw.split('=== ORACLE_DISK ===')[1]?.split('=== MINIO ===')[0]?.trim();
  if (diskLine) oracleDiskPct = diskLine.split(/\s+/)[4] || '?';
  const pct = parseInt(oracleDiskPct);
  if (pct > 80) alerts.push(`Oracle 디스크 ${oracleDiskPct} (80% 초과)`);
} catch(e) {}

// MinIO 스토리지
let minioSize = '?';
try {
  const minioLine = oracleRaw.split('=== MINIO ===')[1]?.trim();
  if (minioLine && !minioLine.includes('unavailable')) minioSize = minioLine;
} catch(e) {}

// 미니PC 디스크
let miniSsd = '?', miniHdd = '?';
try {
  const ssdLine = minipcRaw.split('=== SSD ===')[1]?.split('=== HDD ===')[0]?.trim();
  if (ssdLine) miniSsd = ssdLine.split(/\s+/)[4] || '?';
  const hddLine = minipcRaw.split('=== HDD ===')[1]?.trim();
  if (hddLine) miniHdd = hddLine.split(/\s+/)[4] || '?';
  if (parseInt(miniSsd) > 80) alerts.push(`미니PC SSD ${miniSsd} (80% 초과)`);
  if (parseInt(miniHdd) > 80) alerts.push(`미니PC HDD ${miniHdd} (80% 초과)`);
} catch(e) {}

// n8n 실행 횟수 (지난 7일)
const weekExecs = execData.filter(e => new Date(e.startedAt) > weekStart);
const totalExecs = weekExecs.length;
const errorExecs = weekExecs.filter(e => e.status === 'error').length;

// MakeShop API 추정 (n8n 실행 중 makeshop 관련)
const makeshopExecs = weekExecs.filter(e => {
  const name = (e.workflowData?.name || '').toLowerCase();
  return name.includes('fa-') || name.includes('makeshop') || name.includes('s3a') || name.includes('review');
}).length;

// NocoDB 레코드 (직접 저장)
const record = {
  week: now.toISOString().split('T')[0],
  sms_remain: smsNum || 0,
  lms_remain: parseInt(lmsRemain) || 0,
  oracle_disk_pct: parseInt(oracleDiskPct) || 0,
  minio_size: minioSize,
  minipc_ssd_pct: parseInt(miniSsd) || 0,
  minipc_hdd_pct: parseInt(miniHdd) || 0,
  n8n_execs_7d: totalExecs,
  n8n_errors_7d: errorExecs,
  makeshop_api_est: makeshopExecs * 3,
  alerts: alerts.join('; ') || 'none'
};

// 텔레그램 메시지
let msg = `\ud83d\udcc8 주간 API/리소스 리포트 (${now.toLocaleDateString('ko-KR', {timeZone:'Asia/Seoul'})})\n\n`;
msg += `\ud83d\udce9 SMS: ${smsRemain}건 / LMS: ${lmsRemain}건\n`;
msg += `\ud83d\udda5\ufe0f Oracle: ${oracleDiskPct} / MinIO: ${minioSize}\n`;
msg += `\ud83d\udcbe 미니PC: SSD ${miniSsd} / HDD ${miniHdd}\n`;
msg += `\u2699\ufe0f n8n 7일: ${totalExecs}건 실행 / ${errorExecs}건 에러\n`;
msg += `\ud83d\uded2 MakeShop API 추정: ~${makeshopExecs * 3}회/주\n`;

if (alerts.length > 0) {
  msg += `\n\u26a0\ufe0f 경고:\n`;
  alerts.forEach(a => msg += `  \u2022 ${a}\n`);
}

return [{ json: { message: msg, record } }];
